'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes, ReactNode } from 'react'
import { Section } from '../../section/section'
import styles from './hero.module.css'

type HeadingLevel = 1 | 2 | 3

export interface HeroProps extends Omit<HTMLAttributes<HTMLElement>, 'title'> {
  variant?: 'centered' | 'split'
  /** Small mono line above the title. */
  eyebrow?: ReactNode
  title: ReactNode
  description?: ReactNode
  /** Buttons/links rendered in a row under the description. */
  actions?: ReactNode
  /** Right-hand slot in the split variant (image, demo, code). */
  media?: ReactNode
  headingLevel?: HeadingLevel
  className?: string | undefined
}

export function Hero({
  variant = 'centered',
  eyebrow,
  title,
  description,
  actions,
  media,
  headingLevel = 1,
  className,
  ...props
}: HeroProps) {
  const Heading = `h${headingLevel}` as const
  return (
    <Section className={cn(styles['hero'], className)} data-variant={variant} {...props}>
      <div className={styles['copy']}>
        {eyebrow && <p className={styles['eyebrow']}>{eyebrow}</p>}
        <Heading className={styles['title']}>{title}</Heading>
        {description && <p className={styles['description']}>{description}</p>}
        {actions && <div className={styles['actions']}>{actions}</div>}
      </div>
      {variant === 'split' && media && <div className={styles['media']}>{media}</div>}
    </Section>
  )
}

@layer cascivo.component {
  /* centered: single column, text centered */
  .hero[data-variant='centered'] .copy {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
    gap: var(--cascivo-space-4);
  }

  /* split: two-column grid */
  .hero[data-variant='split'] {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: var(--cascivo-space-10);
    align-items: center;

    @container (max-inline-size: 48rem) {
      grid-template-columns: 1fr;
    }
  }

  .hero[data-variant='split'] .copy {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-4);
  }

  .eyebrow {
    font-size: var(--cascivo-text-sm);
    font-family: var(--cascivo-font-mono);
    color: var(--cascivo-text-secondary);
    margin: 0;
  }

  .title {
    font-size: var(--cascivo-text-4xl);
    font-weight: var(--cascivo-font-bold);
    text-wrap: balance;
    margin: 0;
  }

  .description {
    font-size: var(--cascivo-text-lg);
    color: var(--cascivo-text-secondary);
    max-inline-size: 60ch;
    margin: 0;
  }

  .hero[data-variant='centered'] .description {
    margin-inline: auto;
  }

  .actions {
    display: flex;
    flex-wrap: wrap;
    gap: var(--cascivo-space-3);
  }

  .hero[data-variant='centered'] .actions {
    justify-content: center;
  }

  .media {
    display: flex;
    align-items: center;
    justify-content: center;
  }
}
